## 測試檔案

### PrismTests/Domain/FilterPresetTests.swift

```swift
import Testing
@testable import Prism

struct FilterPresetTests {
    @Test func allPresetsHaveValidParameters() {
        let all = FilterPresetProvider.all
        #expect(all.count >= 30)
        for preset in all {
            #expect(!preset.id.isEmpty)
            #expect(!preset.name.isEmpty)
            #expect(preset.parameters.contrast >= 0)
            #expect(preset.parameters.contrast <= 2)
            #expect(preset.parameters.saturation >= 0)
        }
    }

    @Test func categoriesAreCorrect() {
        let bwPresets = FilterPresetProvider.all.filter { $0.category == .bw }
        for preset in bwPresets {
            #expect(preset.parameters.saturation == 0)
        }
    }

    @Test func presetIDsAreUnique() {
        let ids = FilterPresetProvider.all.map { $0.id }
        #expect(Set(ids).count == ids.count)
    }
}
```

