### PrismTests/Data/ImageProcessingTests.swift

```swift
struct ImageProcessingTests {
    let service = ImageProcessingService()

    @Test func thumbnailGeneration() async throws {
        // 建立一個 1x1 紅色像素的測試圖片
        let testImage = createTestImage(width: 100, height: 100, color: .red)
        let data = testImage.jpegData(compressionQuality: 1.0)!

        let thumbnail = try await service.generateThumbnail(from: data, size: CGSize(width: 50, height: 50))
        #expect(!thumbnail.isEmpty)
    }

    @Test func filterApplication() async throws {
        let testImage = createTestImage(width: 100, height: 100, color: .blue)
        let data = testImage.jpegData(compressionQuality: 1.0)!
        let preset = FilterPresetProvider.classic.first!

        let result = try await service.applyFilter(preset, to: data, intensity: 1.0)
        #expect(!result.isEmpty)
        #expect(result != data)  // 確認有變化
    }

    @Test func adjustmentApplication() async throws {
        let testImage = createTestImage(width: 100, height: 100, color: .green)
        let data = testImage.jpegData(compressionQuality: 1.0)!
        var params = AdjustmentParams()
        params.brightness = 0.5

        let result = try await service.applyAdjustments(params, to: data)
        #expect(!result.isEmpty)
    }

    // Helper
    private func createTestImage(width: Int, height: Int, color: UIColor) -> UIImage {
        UIGraphicsImageRenderer(size: CGSize(width: width, height: height)).image { ctx in
            color.setFill()
            ctx.fill(CGRect(x: 0, y: 0, width: width, height: height))
        }
    }
}
```

